+// ---------------------------------------------------------------------------
+// Wiener index
+// ---------------------------------------------------------------------------
+
+/// Wiener index: sum of all pairwise shortest path distances.
+///
+/// Returns `None` if the graph is disconnected.
+#[must_use]
+pub fn wiener_index(graph: &Graph) -> Option<f64> {
+    let nodes = graph.nodes_ordered();
+    let n = nodes.len();
+    if n < 2 {
+        return Some(0.0);
+    }
+
+    let idx: std::collections::HashMap<&str, usize> =
+        nodes.iter().enumerate().map(|(i, n)| (*n, i)).collect();
+
+    let mut total = 0.0;
+    for s in 0..n {
+        // BFS from node s
+        let mut dist = vec![usize::MAX; n];
+        dist[s] = 0;
+        let mut queue = std::collections::VecDeque::new();
+        queue.push_back(s);
+        let mut reached = 0usize;
+
+        while let Some(v) = queue.pop_front() {
+            reached += 1;
+            if let Some(nbrs) = graph.neighbors(nodes[v]) {
+                for nb in nbrs {
+                    let ni = idx[nb];
+                    if dist[ni] == usize::MAX {
+                        dist[ni] = dist[v] + 1;
+                        queue.push_back(ni);
+                    }
+                }
+            }
+        }
+
+        if reached < n {
+            return None; // Disconnected
+        }
+
+        // Only count s < t to avoid double counting
+        for t in (s + 1)..n {
+            total += dist[t] as f64;
+        }
+    }
+
+    Some(total)
+}
